insert into QuotationEstimation(
PolicyKey VersionSequence TransactionSequence TotalPremium TotalPremiumFirstRange TotalPolicyTaxAmount InvoicedPremium TotalPolicyModifierPercentage IsClaimOptionType IsClaimExpensesType IsDollarDefense AggregateLimit OccuranceLimit AggregateDeductible OccuranceDeductible IsMinimumPremium XmlOutputDatafromRating XmlInputDatatoRating LastUpdateUserID LastUpdateTimeStamp VersionKey CreatedDate CreatedBy
) values (
#PolicyKey# #VersionSequence# #TransactionSequence# #TotalPremium# #TotalPremiumFirstRange# #TotalPolicyTaxAmount# #InvoicedPremium# #TotalPolicyModifierPercentage# #IsClaimOptionType# #IsClaimExpensesType# #IsDollarDefense# #AggregateLimit# #OccuranceLimit# #AggregateDeductible# #OccuranceDeductible# #IsMinimumPremium# #XmlOutputDatafromRating# #XmlInputDatatoRating# #LastUpdateUserID# #LastUpdateTimeStamp# #VersionKey# #CreatedDate# #CreatedBy#
) SELECT IDENT_CURRENT('QuotationEstimation') as last_insert_id
